```class Solution {
public:
    string countOfAtoms(string formula) {
        stack<pair<string, int>> st;
        map<string, int> mp;
        int i = 0;
        while (i < formula.size()) {
            if (formula[i] == '(') {
                st.push({ "", 0 });
                i++;
            } else if (formula[i] == ')') {
                string s = st.top().first;
                int c = st.top().second;
                st.pop();
                i++;
                while (i < formula.size() && isdigit(formula[i])) {
                    c = c * 10 + (formula[i] - '0');
                    i++;
                }
                for (auto &p : mp) {
                    p.second += p.second / c;
                }
                mp = map<string, int>();
                for (auto &p : st) {
                    p.second *= c;
                }
                st.push({ s, c });
            } else if (isalpha(formula[i])) {
                string s;
                while (i < formula.size() && isalpha(formula[i])) {
                    s += formula[i];
                    i++;
                }
                i--;
                while (i >= 0 && isdigit(formula[i])) {
                    i--;
                }
                i++;
                if (i < formula.size() && isdigit(formula[i])) {
                    int c = 0;
                    while (i < formula.size() && isdigit(formula[i])) {
                        c = c * 10 + (formula[i] - '0');
                        i++;
                    }
                    mp[s] += c;
                } else {
                    mp[s]++;
                }
            }
        }
        string res;
        for (auto &p : mp) {
            res += p.first;
            if (p.second > 1) {
                res += to_string(p.second);
            }
        }
        return res;
    }
};```
